using UnityEngine;

/// <summary>
/// Przeciwnik w stylu DOOM bez NavMesh.
/// Ruch: Rigidbody + omijanie przeszkód raycastami.
/// Podepnij na tym samym GameObject co Rigidbody + CapsuleCollider.
/// </summary>
[RequireComponent(typeof(Rigidbody))]
[RequireComponent(typeof(CapsuleCollider))]
public class SimpleEnemyAI : MonoBehaviour
{
    // ─── Ustawienia w Inspectorze ────────────────────────────────────────────────

    [Header("Ruch")]
    public float moveSpeed = 3f;
    public float rotateSpeed = 8f;

    [Header("Wykrywanie gracza")]
    public float detectionRange = 15f;
    public float attackRange = 1.8f;
    public string playerTag = "Player";

    [Header("Atak")]
    public float attackDamage = 10f;
    public float attackCooldown = 1.5f;

    [Header("Zdrowie")]
    public float maxHealth = 100f;

    [Header("Omijanie przeszkód")]
    [Tooltip("Długość raycastów do wykrywania ścian")]
    public float rayLength = 2f;
    [Tooltip("Ile raycastów w wachlarzu (nieparzysta liczba)")]
    public int rayCount = 5;
    [Tooltip("Kąt wachlarza raycastów")]
    public float raySpread = 90f;

    [Header("Grawitacja")]
    [Tooltip("Siła przyciągania do podłogi")]
    public float gravityMultiplier = 3f;

    // ─── Prywatne ────────────────────────────────────────────────────────────────

    private Rigidbody rb;
    private Transform player;
    private float currentHealth;
    private float attackTimer;

    private enum State { Idle, Chasing, Attacking, Dead }
    private State state = State.Idle;

    // Kierunek omijania przeszkody (smooth steering)
    private Vector3 steeringDir;

    void Awake()
    {
        rb = GetComponent<Rigidbody>();
        rb.freezeRotation = true;           // nie przewracaj się
        rb.useGravity = false;              // własna grawitacja
        rb.interpolation = RigidbodyInterpolation.Interpolate;
        rb.collisionDetectionMode = CollisionDetectionMode.Continuous;

        currentHealth = maxHealth;
    }

    void Start()
    {
        GameObject p = GameObject.FindGameObjectWithTag(playerTag);
        if (p != null) player = p.transform;
    }

    void Update()
    {
        if (state == State.Dead) return;
        if (player == null) return;

        float dist = Vector3.Distance(transform.position, player.position);

        // Maszyna stanów
        switch (state)
        {
            case State.Idle:
                if (dist <= detectionRange)
                    state = State.Chasing;
                break;

            case State.Chasing:
                if (dist <= attackRange)
                    state = State.Attacking;
                else if (dist > detectionRange)
                    state = State.Idle;
                else
                    Chase();
                break;

            case State.Attacking:
                if (dist > attackRange)
                {
                    state = State.Chasing;
                }
                else
                {
                    FacePlayer();
                    TryAttack();
                }
                break;
        }

        ApplyGravity();

        if (attackTimer > 0f)
            attackTimer -= Time.deltaTime;
    }

    // ─── Ruch ────────────────────────────────────────────────────────────────────

    void Chase()
    {
        FacePlayer();

        // Raycasty do wykrywania ścian
        Vector3 moveDir = GetSteeringDirection();

        // Przesuń przez Rigidbody (nie przez Transform – fizyka działa)
        Vector3 vel = moveDir * moveSpeed;
        vel.y = rb.linearVelocity.y;
        rb.linearVelocity = vel;
    }

    void FacePlayer()
    {
        Vector3 dir = (player.position - transform.position);
        dir.y = 0;
        if (dir == Vector3.zero) return;

        Quaternion targetRot = Quaternion.LookRotation(dir);
        transform.rotation = Quaternion.Slerp(
            transform.rotation,
            targetRot,
            rotateSpeed * Time.deltaTime
        );
    }

    void ApplyGravity()
    {
        rb.AddForce(Physics.gravity * gravityMultiplier, ForceMode.Acceleration);
    }

    // ─── Steering (omijanie ścian) ────────────────────────────────────────────────

    Vector3 GetSteeringDirection()
    {
        Vector3 toPlayer = (player.position - transform.position);
        toPlayer.y = 0;
        toPlayer.Normalize();

        // Rozstrzel wachlarz raycastów
        float bestScore = float.MinValue;
        Vector3 bestDir = toPlayer;

        for (int i = 0; i < rayCount; i++)
        {
            // Kąt od -spread/2 do +spread/2
            float t = rayCount > 1 ? (float)i / (rayCount - 1) : 0.5f;
            float angle = Mathf.Lerp(-raySpread / 2f, raySpread / 2f, t);
            Vector3 dir = Quaternion.Euler(0, angle, 0) * toPlayer;

            bool blocked = Physics.Raycast(
                transform.position + Vector3.up * 0.5f,
                dir,
                rayLength
            );

            // Premiuj kierunki bliżej gracza i wolne od ścian
            float dot = Vector3.Dot(dir, toPlayer);
            float score = dot + (blocked ? -2f : 0f);

            if (score > bestScore)
            {
                bestScore = score;
                bestDir = blocked ? Vector3.zero : dir;
            }
        }

        // Jeśli wszystko zablokowane – stój
        return bestDir;
    }

    // ─── Atak ─────────────────────────────────────────────────────────────────────

    void TryAttack()
    {
        if (attackTimer > 0f) return;

        attackTimer = attackCooldown;
        player.GetComponent<PlayerHealth>()?.TakeDamage(attackDamage);
        Debug.Log($"[Enemy] Atak! Obrażenia: {attackDamage}");
    }

    // ─── Trafienie / śmierć ───────────────────────────────────────────────────────

    public void TakeDamage(float damage)
    {
        if (state == State.Dead) return;

        currentHealth -= damage;
        Debug.Log($"[Enemy] HP: {currentHealth}/{maxHealth}");

        // Wróg usłyszał gracza
        if (state == State.Idle)
            state = State.Chasing;

        if (currentHealth <= 0f)
            Die();
    }

    void Die()
    {
        state = State.Dead;
        rb.linearVelocity = Vector3.zero;
        GetComponent<Collider>().enabled = false;
        Destroy(gameObject, 2f);
        Debug.Log("[Enemy] Zginął!");
    }

    // ─── Gizmos ───────────────────────────────────────────────────────────────────

    void OnDrawGizmosSelected()
    {
        // Zasięg detekcji
        Gizmos.color = Color.yellow;
        Gizmos.DrawWireSphere(transform.position, detectionRange);

        // Zasięg ataku
        Gizmos.color = Color.red;
        Gizmos.DrawWireSphere(transform.position, attackRange);

        // Raycasty steeringu
        if (!Application.isPlaying) return;
        if (player == null) return;

        Vector3 toPlayer = (player.position - transform.position);
        toPlayer.y = 0;
        toPlayer.Normalize();

        Gizmos.color = Color.cyan;
        for (int i = 0; i < rayCount; i++)
        {
            float t = rayCount > 1 ? (float)i / (rayCount - 1) : 0.5f;
            float angle = Mathf.Lerp(-raySpread / 2f, raySpread / 2f, t);
            Vector3 dir = Quaternion.Euler(0, angle, 0) * toPlayer;
            Gizmos.DrawRay(transform.position + Vector3.up * 0.5f, dir * rayLength);
        }
    }
}

using UnityEngine;

/// <summary>
/// Przeciwnik w stylu DOOM bez NavMesh.
/// Ruch: Rigidbody + omijanie przeszkód raycastami.
/// Podepnij na tym samym GameObject co Rigidbody + CapsuleCollider.
/// </summary>
[RequireComponent(typeof(Rigidbody))]
[RequireComponent(typeof(CapsuleCollider))]
public class SimpleEnemyAI : MonoBehaviour
{
    // ─── Ustawienia w Inspectorze ────────────────────────────────────────────────

    [Header("Ruch")]
    public float moveSpeed = 3f;
    public float rotateSpeed = 8f;

    [Header("Wykrywanie gracza")]
    public float detectionRange = 15f;
    public float attackRange = 1.8f;
    public string playerTag = "Player";

    [Header("Atak")]
    public float attackDamage = 10f;
    public float attackCooldown = 1.5f;

    [Header("Zdrowie")]
    public float maxHealth = 100f;

    [Header("Omijanie przeszkód")]
    [Tooltip("Długość raycastów do wykrywania ścian")]
    public float rayLength = 2f;
    [Tooltip("Ile raycastów w wachlarzu (nieparzysta liczba)")]
    public int rayCount = 5;
    [Tooltip("Kąt wachlarza raycastów")]
    public float raySpread = 90f;

    [Header("Grawitacja")]
    [Tooltip("Siła przyciągania do podłogi")]
    public float gravityMultiplier = 3f;

    // ─── Prywatne ────────────────────────────────────────────────────────────────

    private Rigidbody rb;
    private Transform player;
    private float currentHealth;
    private float attackTimer;
    private float boundTimer;

    private enum State { Idle, Chasing, Attacking, Dead }
    private State state = State.Idle;

    public bool IsBound => boundTimer > 0f;

    // Kierunek omijania przeszkody (smooth steering)
    private Vector3 steeringDir;

    void Awake()
    {
        rb = GetComponent<Rigidbody>();
        rb.freezeRotation = true;           // nie przewracaj się
        rb.useGravity = false;              // własna grawitacja
        rb.interpolation = RigidbodyInterpolation.Interpolate;
        rb.collisionDetectionMode = CollisionDetectionMode.Continuous;

        currentHealth = maxHealth;
    }

    void Start()
    {
        GameObject p = GameObject.FindGameObjectWithTag(playerTag);
        if (p != null) player = p.transform;
    }

    void Update()
    {
        if (state == State.Dead) return;

        if (IsBound)
        {
            TickBound();
            return;
        }

        if (player == null) return;

        float dist = Vector3.Distance(transform.position, player.position);

        // Maszyna stanów
        switch (state)
        {
            case State.Idle:
                if (dist <= detectionRange)
                    state = State.Chasing;
                break;

            case State.Chasing:
                if (dist <= attackRange)
                    state = State.Attacking;
                else if (dist > detectionRange)
                    state = State.Idle;
                else
                    Chase();
                break;

            case State.Attacking:
                if (dist > attackRange)
                {
                    state = State.Chasing;
                }
                else
                {
                    FacePlayer();
                    TryAttack();
                }
                break;
        }

        ApplyGravity();

        if (attackTimer > 0f)
            attackTimer -= Time.deltaTime;
    }

    void TickBound()
    {
        boundTimer -= Time.deltaTime;
        rb.linearVelocity = new Vector3(0f, rb.linearVelocity.y, 0f);
        ApplyGravity();

        if (boundTimer <= 0f)
            ReleaseFromBind();
    }

    // ─── Ruch ────────────────────────────────────────────────────────────────────

    void Chase()
    {
        FacePlayer();

        // Raycasty do wykrywania ścian
        Vector3 moveDir = GetSteeringDirection();

        // Przesuń przez Rigidbody (nie przez Transform – fizyka działa)
        Vector3 vel = moveDir * moveSpeed;
        vel.y = rb.linearVelocity.y;
        rb.linearVelocity = vel;
    }

    void FacePlayer()
    {
        Vector3 dir = (player.position - transform.position);
        dir.y = 0;
        if (dir == Vector3.zero) return;

        Quaternion targetRot = Quaternion.LookRotation(dir);
        transform.rotation = Quaternion.Slerp(
            transform.rotation,
            targetRot,
            rotateSpeed * Time.deltaTime
        );
    }

    void ApplyGravity()
    {
        rb.AddForce(Physics.gravity * gravityMultiplier, ForceMode.Acceleration);
    }

    // ─── Steering (omijanie ścian) ────────────────────────────────────────────────

    Vector3 GetSteeringDirection()
    {
        Vector3 toPlayer = (player.position - transform.position);
        toPlayer.y = 0;
        toPlayer.Normalize();

        // Rozstrzel wachlarz raycastów
        float bestScore = float.MinValue;
        Vector3 bestDir = toPlayer;

        for (int i = 0; i < rayCount; i++)
        {
            // Kąt od -spread/2 do +spread/2
            float t = rayCount > 1 ? (float)i / (rayCount - 1) : 0.5f;
            float angle = Mathf.Lerp(-raySpread / 2f, raySpread / 2f, t);
            Vector3 dir = Quaternion.Euler(0, angle, 0) * toPlayer;

            bool blocked = Physics.Raycast(
                transform.position + Vector3.up * 0.5f,
                dir,
                rayLength
            );

            // Premiuj kierunki bliżej gracza i wolne od ścian
            float dot = Vector3.Dot(dir, toPlayer);
            float score = dot + (blocked ? -2f : 0f);

            if (score > bestScore)
            {
                bestScore = score;
                bestDir = blocked ? Vector3.zero : dir;
            }
        }

        // Jeśli wszystko zablokowane – stój
        return bestDir;
    }

    // ─── Atak ─────────────────────────────────────────────────────────────────────

    void TryAttack()
    {
        if (attackTimer > 0f) return;

        attackTimer = attackCooldown;
        player.GetComponent<PlayerHealth>()?.TakeDamage(attackDamage);
        Debug.Log($"[Enemy] Atak! Obrażenia: {attackDamage}");
    }

    // ─── Trafienie / śmierć ───────────────────────────────────────────────────────

    public void TakeDamage(float damage)
    {
        if (state == State.Dead) return;

        currentHealth -= damage;
        Debug.Log($"[Enemy] HP: {currentHealth}/{maxHealth}");

        // Wróg usłyszał gracza
        if (state == State.Idle)
            state = State.Chasing;

        if (currentHealth <= 0f)
            Die();
    }

    public void Bind(float duration)
    {
        if (state == State.Dead)
            return;

        boundTimer = Mathf.Max(boundTimer, duration);
        rb.linearVelocity = Vector3.zero;
    }

    void ReleaseFromBind()
    {
        boundTimer = 0f;

        if (state == State.Dead)
            return;

        if (player == null)
        {
            state = State.Idle;
            return;
        }

        float dist = Vector3.Distance(transform.position, player.position);
        state = dist <= detectionRange ? State.Chasing : State.Idle;
    }

    void Die()
    {
        state = State.Dead;
        rb.linearVelocity = Vector3.zero;
        GetComponent<Collider>().enabled = false;
        Destroy(gameObject, 2f);
        Debug.Log("[Enemy] Zginął!");
    }

    // ─── Gizmos ───────────────────────────────────────────────────────────────────

    void OnDrawGizmosSelected()
    {
        // Zasięg detekcji
        Gizmos.color = Color.yellow;
        Gizmos.DrawWireSphere(transform.position, detectionRange);

        // Zasięg ataku
        Gizmos.color = Color.red;
        Gizmos.DrawWireSphere(transform.position, attackRange);

        // Raycasty steeringu
        if (!Application.isPlaying) return;
        if (player == null) return;

        Vector3 toPlayer = (player.position - transform.position);
        toPlayer.y = 0;
        toPlayer.Normalize();

        Gizmos.color = Color.cyan;
        for (int i = 0; i < rayCount; i++)
        {
            float t = rayCount > 1 ? (float)i / (rayCount - 1) : 0.5f;
            float angle = Mathf.Lerp(-raySpread / 2f, raySpread / 2f, t);
            Vector3 dir = Quaternion.Euler(0, angle, 0) * toPlayer;
            Gizmos.DrawRay(transform.position + Vector3.up * 0.5f, dir * rayLength);
        }
    }
}

using UnityEngine;

[RequireComponent(typeof(SpriteRenderer))]
[RequireComponent(typeof(Rigidbody))]
[RequireComponent(typeof(Collider))]
public class Line : MonoBehaviour
{
    private Rigidbody _rb;

    [SerializeField] private float speed = 30f;
    [SerializeField] private float lifetime = 2f;

    [Header("Visual")]
    [SerializeField] private Texture2D tex1;

    [SerializeField] private SpriteRenderer targetSpriteRenderer;

    [Header("Debug")]
    [SerializeField] private bool debugLogs = false;

    [Header("Orientation")]
    [Tooltip("Jeśli włączone, lina będzie billboardem do kamery (zawsze czytelna) i ustawiona poziomo.")]
    [SerializeField] private bool alignToCamera = true;

    [Tooltip("Billboard tylko w poziomie (yaw). Ignoruje pitch kamery, więc nie wygląda jak lecąca deska.")]
    [SerializeField] private bool billboardYawOnly = true;

    [Tooltip("Dodatkowy obrót wokół osi 'forward' kamery (roll) w stopniach. Często 90 lub 0, zależnie jak jest narysowana tekstura.")]
    [SerializeField] private float rollDegrees = 0f;

    private Camera _mainCam;

    private float _age;

    private static Material _cachedSpriteMaterial;

    private void Awake()
    {
        _rb = GetComponent<Rigidbody>();
        _rb.useGravity = false;
        _rb.collisionDetectionMode = CollisionDetectionMode.ContinuousDynamic;

        if (targetSpriteRenderer == null)
            targetSpriteRenderer = GetComponent<SpriteRenderer>();

        EnsureSpriteMaterial(targetSpriteRenderer);


        targetSpriteRenderer.sortingOrder = 500;

        if (tex1 == null)
        {
            Debug.LogWarning("[Line] tex1 is null - lina nie będzie widoczna. Przypnij teksturę w Line.prefab.");
        }
        else
        {
            var spr = CreateSprite(tex1);
            if (spr != null)
                targetSpriteRenderer.sprite = spr;
        }


        if (transform.localScale == Vector3.one)
            transform.localScale = Vector3.one * 0.25f;

        var col = GetComponent<Collider>();
        col.isTrigger = true;

        _mainCam = Camera.main;
        if (_mainCam == null)
            _mainCam = FindFirstObjectByType<Camera>();
    }

    private void OnEnable()
    {
        _age = 0f;
    }

    public void Launch(Vector3 direction, float? overrideSpeed = null, float? overrideLifetime = null)
    {
        if (direction.sqrMagnitude < 0.0001f)
            direction = transform.forward;

        speed = overrideSpeed ?? speed;
        lifetime = overrideLifetime ?? lifetime;

        _age = 0f;


        if (targetSpriteRenderer != null && targetSpriteRenderer.sprite == null && tex1 != null)
        {
            var spr = CreateSprite(tex1);
            if (spr != null)
                targetSpriteRenderer.sprite = spr;
        }

        direction = direction.normalized;
        transform.forward = direction;

        _rb.isKinematic = false;
        _rb.WakeUp();


        _rb.linearVelocity = direction * speed;

        if (debugLogs)
            Debug.Log($"[Line] Launch speed={speed} lifetime={lifetime} vel={_rb.linearVelocity} pos={transform.position}");
    }

    private void Update()
    {
        _age += Time.deltaTime;
        if (_age >= lifetime)
        {
            Destroy(gameObject);
            return;
        }

        if (alignToCamera)
            AlignSpriteToCamera();
    }

    private void AlignSpriteToCamera()
    {
        if (_mainCam == null)
            return;

        var camPos = _mainCam.transform.position;
        var toCam = camPos - transform.position;
        if (toCam.sqrMagnitude < 0.0001f)
            return;

        Quaternion look;

        if (billboardYawOnly)
        {
            // tylko obrót w poziomie: usuń składową Y, żeby nie reagować na pitch
            toCam.y = 0f;
            if (toCam.sqrMagnitude < 0.0001f)
                return;

            look = Quaternion.LookRotation(toCam.normalized, Vector3.up);
        }
        else
        {
            // pełny billboard (pitch+yaw)
            look = Quaternion.LookRotation(toCam, Vector3.up);
        }

        // roll - żeby tekstura była poziomo
        if (Mathf.Abs(rollDegrees) > 0.001f)
            look *= Quaternion.AngleAxis(rollDegrees, Vector3.forward);

        transform.rotation = look;
    }

    private void OnTriggerEnter(Collider other)
    {
        // Najprościej i bez tagów: sprawdź, czy to jest wróg po komponencie
        if (other.GetComponentInParent<DoomEnemyController>() != null || other.GetComponentInParent<SimpleEnemyAI>() != null)
        {
            Debug.Log($"[Line] Trafiono enemy: {other.name}");
            Destroy(gameObject);
        }
    }

    private static void EnsureSpriteMaterial(SpriteRenderer sr)
    {
        if (sr == null)
            return;

        var mat = sr.sharedMaterial;
        if (mat != null && mat.shader != null)
            return;

        if (_cachedSpriteMaterial == null)
        {
            var urp2d = Shader.Find("Universal Render Pipeline/2D/Sprite-Unlit-Default");
            if (urp2d != null)
                _cachedSpriteMaterial = new Material(urp2d);
            else
            {
                var builtin = Shader.Find("Sprites/Default");
                if (builtin != null)
                    _cachedSpriteMaterial = new Material(builtin);
            }
        }

        if (_cachedSpriteMaterial != null)
            sr.sharedMaterial = _cachedSpriteMaterial;
    }

    private static Sprite CreateSprite(Texture2D t)
    {
        if (t == null)
            return null;

        return Sprite.Create(t, new Rect(0, 0, t.width, t.height), new Vector2(0.5f, 0.5f), 100f);
    }
}

using System;
using UnityEngine;

[RequireComponent(typeof(Rigidbody))]
public class Line : MonoBehaviour
{
    private enum LineState
    {
        Idle,
        Extending,
        Attached,
        Retracting,
        Finished
    }

    private Rigidbody _rb;

    [Header("Travel")]
    [SerializeField, Min(0.01f)] private float speed = 30f;
    [SerializeField, Min(0.01f)] private float retractSpeed = 40f;
    [SerializeField, Min(0.1f)] private float maxLength = 12f;
    [SerializeField, Min(0f)] private float lifetime = 2f;
    [SerializeField, Min(0.01f)] private float hitRadius = 0.35f;
    [SerializeField, Min(0.01f)] private float finishDistance = 0.2f;

    [Header("Visual")]
    [SerializeField] private Texture2D tex1;
    [SerializeField] private SpriteRenderer targetSpriteRenderer;

    [Header("Debug")]
    [SerializeField] private bool debugLogs = false;

    [Header("Orientation")]
    [Tooltip("Jeśli włączone, powierzchnia liny będzie obracana w stronę kamery, żeby nie znikała pod kątem.")]
    [SerializeField] private bool alignToCamera = true;

    [Tooltip("Dodatkowy obrót liny wokół osi długości.")]
    [SerializeField] private float rollDegrees = 0f;

    private Camera _mainCam;
    private Renderer[] _cachedRenderers = Array.Empty<Renderer>();
    private Collider[] _cachedColliders = Array.Empty<Collider>();
    private Collider[] _ownerColliders = Array.Empty<Collider>();
    private Vector3 _initialLocalScale;
    private float _baseLocalForwardLength = 1f;
    private LineState _state = LineState.Idle;
    private Transform _owner;
    private Vector3 _originLocalOffset;
    private Vector3 _fallbackOrigin;
    private Vector3 _tipPoint;
    private Vector3 _direction;
    private float _activeMaxLength;
    private float _activeBindDuration;
    private float _activeRetractSpeed;
    private float _attachTimer;
    private Transform _boundTarget;
    private Vector3 _boundLocalPoint;

    private static Material _cachedSpriteMaterial;

    public bool IsFinished => _state == LineState.Finished;

    private void Awake()
    {
        _rb = GetComponent<Rigidbody>();
        _rb.useGravity = false;
        _rb.isKinematic = true;
        _rb.linearVelocity = Vector3.zero;
        _rb.angularVelocity = Vector3.zero;

        if (targetSpriteRenderer == null)
            targetSpriteRenderer = GetComponent<SpriteRenderer>();

        if (targetSpriteRenderer != null)
        {
            EnsureSpriteMaterial(targetSpriteRenderer);
            targetSpriteRenderer.sortingOrder = 500;

            if (tex1 == null)
            {
                Debug.LogWarning("[Line] tex1 is null - lina może być niewidoczna. Przypnij teksturę w Line.prefab.");
            }
            else if (targetSpriteRenderer.sprite == null)
            {
                var spr = CreateSprite(tex1);
                if (spr != null)
                    targetSpriteRenderer.sprite = spr;
            }
        }

        _cachedRenderers = GetComponentsInChildren<Renderer>(true);
        _cachedColliders = GetComponentsInChildren<Collider>(true);
        _initialLocalScale = transform.localScale;
        _baseLocalForwardLength = Mathf.Max(CalculateLocalForwardLength(), 0.01f);

        foreach (var col in _cachedColliders)
            col.enabled = false;

        CacheMainCamera();
        SetVisible(false);
    }

    public void Launch(
        Transform owner,
        Vector3 originLocalOffset,
        Vector3 direction,
        float? overrideSpeed = null,
        float? overrideMaxLength = null,
        float? overrideBindDuration = null,
        float? overrideRetractSpeed = null)
    {
        _owner = owner;
        _originLocalOffset = originLocalOffset;
        _ownerColliders = owner != null ? owner.GetComponentsInChildren<Collider>(true) : Array.Empty<Collider>();
        _fallbackOrigin = owner != null ? owner.TransformPoint(originLocalOffset) : transform.position;

        if (direction.sqrMagnitude < 0.0001f)
            direction = owner != null ? owner.forward : transform.forward;

        speed = overrideSpeed ?? speed;
        _activeMaxLength = overrideMaxLength ?? maxLength;
        _activeBindDuration = overrideBindDuration ?? lifetime;
        _activeRetractSpeed = overrideRetractSpeed ?? retractSpeed;

        _direction = direction.normalized;
        _tipPoint = GetOriginPoint();
        _boundTarget = null;
        _attachTimer = 0f;
        _state = LineState.Extending;

        UpdateVisual();

        if (debugLogs)
        {
            Debug.Log($"[Line] Launch speed={speed}, maxLength={_activeMaxLength}, bindDuration={_activeBindDuration}, retractSpeed={_activeRetractSpeed}, origin={_tipPoint}, dir={_direction}");
        }
    }

    private void Update()
    {
        if (IsFinished)
            return;

        if (_mainCam == null)
            CacheMainCamera();

        switch (_state)
        {
            case LineState.Extending:
                TickExtending();
                break;

            case LineState.Attached:
                TickAttached();
                break;

            case LineState.Retracting:
                TickRetracting();
                break;
        }

        UpdateVisual();
    }

    private void TickExtending()
    {
        var origin = GetOriginPoint();
        var previousTip = _tipPoint;
        _tipPoint += _direction * (speed * Time.deltaTime);

        if (TryFindEnemyHit(previousTip, _tipPoint, out var enemyRoot, out var hitPoint))
        {
            _tipPoint = hitPoint;
            AttachToEnemy(enemyRoot, hitPoint);
            return;
        }

        var currentLength = Vector3.Distance(origin, _tipPoint);
        if (currentLength >= _activeMaxLength)
        {
            var ropeDir = (_tipPoint - origin).sqrMagnitude > 0.0001f
                ? (_tipPoint - origin).normalized
                : _direction;

            _tipPoint = origin + ropeDir * _activeMaxLength;
            StartRetracting();
        }
    }

    private void TickAttached()
    {
        if (_boundTarget == null || !_boundTarget.gameObject.activeInHierarchy)
        {
            StartRetracting();
            return;
        }

        _tipPoint = _boundTarget.TransformPoint(_boundLocalPoint);
        _attachTimer -= Time.deltaTime;

        if (_attachTimer <= 0f)
            StartRetracting();
    }

    private void TickRetracting()
    {
        var origin = GetOriginPoint();
        var toOrigin = origin - _tipPoint;
        var distance = toOrigin.magnitude;

        if (distance <= finishDistance)
        {
            _tipPoint = origin;
            Finish();
            return;
        }

        var step = _activeRetractSpeed * Time.deltaTime;
        if (step >= distance)
        {
            _tipPoint = origin;
            Finish();
            return;
        }

        _tipPoint += toOrigin.normalized * step;
    }

    private void AttachToEnemy(Transform enemyRoot, Vector3 hitPoint)
    {
        _boundTarget = enemyRoot;
        _boundLocalPoint = enemyRoot.InverseTransformPoint(hitPoint);
        _attachTimer = _activeBindDuration;

        var doomEnemy = enemyRoot.GetComponent<DoomEnemyController>();
        if (doomEnemy != null)
            doomEnemy.Bind(_activeBindDuration);

        var simpleEnemy = enemyRoot.GetComponent<SimpleEnemyAI>();
        if (simpleEnemy != null)
            simpleEnemy.Bind(_activeBindDuration);

        if (_activeBindDuration <= 0f)
        {
            StartRetracting();
            return;
        }

        _state = LineState.Attached;

        if (debugLogs)
            Debug.Log($"[Line] Enemy attached: {enemyRoot.name}");
    }

    private void StartRetracting()
    {
        if (_state == LineState.Retracting || _state == LineState.Finished)
            return;

        _boundTarget = null;
        _state = LineState.Retracting;

        if (debugLogs)
            Debug.Log("[Line] Retracting back to player.");
    }

    private void Finish()
    {
        _state = LineState.Finished;
        SetVisible(false);
        Destroy(gameObject);
    }

    private Vector3 GetOriginPoint()
    {
        if (_owner != null)
        {
            _fallbackOrigin = _owner.TransformPoint(_originLocalOffset);
            return _fallbackOrigin;
        }

        return _fallbackOrigin;
    }

    private bool TryFindEnemyHit(Vector3 start, Vector3 end, out Transform enemyRoot, out Vector3 hitPoint)
    {
        enemyRoot = null;
        hitPoint = end;

        var travel = end - start;
        var distance = travel.magnitude;

        if (distance <= 0.0001f)
            return TryFindEnemyInsideSphere(end, out enemyRoot, out hitPoint);

        var hits = Physics.SphereCastAll(start, hitRadius, travel.normalized, distance, ~0, QueryTriggerInteraction.Collide);
        var bestDistance = float.MaxValue;

        foreach (var hit in hits)
        {
            if (hit.collider == null || IsOwnerCollider(hit.collider))
                continue;

            if (!TryGetEnemyRoot(hit.collider, out var root))
                continue;

            if (hit.distance < bestDistance)
            {
                bestDistance = hit.distance;
                enemyRoot = root;
                hitPoint = hit.point;
            }
        }

        if (enemyRoot != null)
            return true;

        return TryFindEnemyInsideSphere(end, out enemyRoot, out hitPoint);
    }

    private bool TryFindEnemyInsideSphere(Vector3 position, out Transform enemyRoot, out Vector3 hitPoint)
    {
        enemyRoot = null;
        hitPoint = position;

        var overlaps = Physics.OverlapSphere(position, hitRadius, ~0, QueryTriggerInteraction.Collide);
        foreach (var overlap in overlaps)
        {
            if (overlap == null || IsOwnerCollider(overlap))
                continue;

            if (!TryGetEnemyRoot(overlap, out var root))
                continue;

            enemyRoot = root;
            hitPoint = overlap.bounds.ClosestPoint(position);
            return true;
        }

        return false;
    }

    private bool TryGetEnemyRoot(Collider col, out Transform enemyRoot)
    {
        enemyRoot = null;

        var doomEnemy = col.GetComponentInParent<DoomEnemyController>();
        if (doomEnemy != null && doomEnemy.enabled)
        {
            enemyRoot = doomEnemy.transform;
            return true;
        }

        var simpleEnemy = col.GetComponentInParent<SimpleEnemyAI>();
        if (simpleEnemy != null && simpleEnemy.enabled)
        {
            enemyRoot = simpleEnemy.transform;
            return true;
        }

        return false;
    }

    private bool IsOwnerCollider(Collider candidate)
    {
        for (var i = 0; i < _ownerColliders.Length; i++)
        {
            if (_ownerColliders[i] == candidate)
                return true;
        }

        return false;
    }

    private void UpdateVisual()
    {
        var origin = GetOriginPoint();
        var ropeVector = _tipPoint - origin;
        var ropeLength = ropeVector.magnitude;

        if (ropeLength <= 0.0001f)
        {
            SetVisible(false);
            return;
        }

        SetVisible(true);

        transform.position = origin + ropeVector * 0.5f;
        transform.rotation = CalculateVisualRotation(ropeVector);

        var scale = _initialLocalScale;
        scale.z = Mathf.Max(0.0001f, _initialLocalScale.z * (ropeLength / _baseLocalForwardLength));
        transform.localScale = scale;
    }

    private Quaternion CalculateVisualRotation(Vector3 ropeVector)
    {
        var forward = ropeVector.normalized;
        var up = Vector3.up;

        if (alignToCamera && _mainCam != null)
        {
            var midpoint = GetOriginPoint() + ropeVector * 0.5f;
            var toCamera = _mainCam.transform.position - midpoint;
            var projectedUp = Vector3.ProjectOnPlane(toCamera, forward);
            if (projectedUp.sqrMagnitude > 0.0001f)
                up = projectedUp.normalized;
        }

        var look = Quaternion.LookRotation(forward, up);
        if (Mathf.Abs(rollDegrees) > 0.001f)
            look *= Quaternion.AngleAxis(rollDegrees, Vector3.forward);

        return look;
    }

    private void SetVisible(bool visible)
    {
        for (var i = 0; i < _cachedRenderers.Length; i++)
            _cachedRenderers[i].enabled = visible;
    }

    private void CacheMainCamera()
    {
        _mainCam = Camera.main;
        if (_mainCam == null)
            _mainCam = FindFirstObjectByType<Camera>();
    }

    private float CalculateLocalForwardLength()
    {
        if (_cachedRenderers.Length == 0)
            return 1f;

        var minZ = float.PositiveInfinity;
        var maxZ = float.NegativeInfinity;

        for (var i = 0; i < _cachedRenderers.Length; i++)
        {
            var bounds = _cachedRenderers[i].bounds;
            var min = bounds.min;
            var max = bounds.max;

            AccumulateLocalZ(new Vector3(min.x, min.y, min.z), ref minZ, ref maxZ);
            AccumulateLocalZ(new Vector3(min.x, min.y, max.z), ref minZ, ref maxZ);
            AccumulateLocalZ(new Vector3(min.x, max.y, min.z), ref minZ, ref maxZ);
            AccumulateLocalZ(new Vector3(min.x, max.y, max.z), ref minZ, ref maxZ);
            AccumulateLocalZ(new Vector3(max.x, min.y, min.z), ref minZ, ref maxZ);
            AccumulateLocalZ(new Vector3(max.x, min.y, max.z), ref minZ, ref maxZ);
            AccumulateLocalZ(new Vector3(max.x, max.y, min.z), ref minZ, ref maxZ);
            AccumulateLocalZ(new Vector3(max.x, max.y, max.z), ref minZ, ref maxZ);
        }

        if (float.IsInfinity(minZ) || float.IsInfinity(maxZ))
            return 1f;

        return Mathf.Max(maxZ - minZ, 0.01f);
    }

    private void AccumulateLocalZ(Vector3 worldPoint, ref float minZ, ref float maxZ)
    {
        var localPoint = transform.InverseTransformPoint(worldPoint);
        minZ = Mathf.Min(minZ, localPoint.z);
        maxZ = Mathf.Max(maxZ, localPoint.z);
    }

    private static void EnsureSpriteMaterial(SpriteRenderer sr)
    {
        if (sr == null)
            return;

        var mat = sr.sharedMaterial;
        if (mat != null && mat.shader != null)
            return;

        if (_cachedSpriteMaterial == null)
        {
            var urp2d = Shader.Find("Universal Render Pipeline/2D/Sprite-Unlit-Default");
            if (urp2d != null)
                _cachedSpriteMaterial = new Material(urp2d);
            else
            {
                var builtin = Shader.Find("Sprites/Default");
                if (builtin != null)
                    _cachedSpriteMaterial = new Material(builtin);
            }
        }

        if (_cachedSpriteMaterial != null)
            sr.sharedMaterial = _cachedSpriteMaterial;
    }

    private static Sprite CreateSprite(Texture2D t)
    {
        if (t == null)
            return null;

        return Sprite.Create(t, new Rect(0, 0, t.width, t.height), new Vector2(0.5f, 0.5f), 100f);
    }
}

using System.Collections;
using Unity.Cinemachine;
using UnityEngine;
using UnityEngine.InputSystem;
using UnityEngine.UI;

[RequireComponent(typeof(AudioSource))]
public class PlayerThrowingLine : MonoBehaviour
{
    [Header("Input")]
    [Tooltip("Akcja pod Q (przełączenie na linę / rzut liną).")]
    [SerializeField] public InputActionReference switchToLine;

    private PlayerShooting _playerShootingScript;

    [Header("UI")]
    [SerializeField] private Image handImage;

    [Tooltip("Opcjonalnie: przypnij UI Image broni. Jeśli puste, skrypt spróbuje znaleźć child 'Gun' w Canvasie.")]
    [SerializeField] private Image gunImage;

    [SerializeField] public Canvas interfaceCanvas;

    [Header("Line Throw Animation")]
    [Tooltip("Czas na każdą klatkę rzutu (tex2->tex3->tex4).")]
    [SerializeField, Min(0f)] private float frameTime = 0.06f;

    [SerializeField] private Texture2D tex1;
    [SerializeField] private Texture2D tex2;
    [SerializeField] private Texture2D tex3;
    [SerializeField] private Texture2D tex4;

    [SerializeField] public AudioClip lineThrowingSound;
    private AudioSource _throwAudio;

    [Header("Line Projectile")]
    [SerializeField] private Line linePrefab;

    [SerializeField] private Transform lineSpawnPoint;

    [SerializeField, Min(0f)] private float rateOfFire = 0.5f;

    [SerializeField] private float lineSpeed = 30f;
    [SerializeField] private float lineLifetime = 2f;

    [Header("Direction")]
    [SerializeField] private CinemachineCamera playerCamera;

    [SerializeField] private float linePitchDegrees = -10f;

    private Coroutine _animCoroutine;
    private Sprite _spr1, _spr2, _spr3, _spr4;

    private float _nextAllowedTime;

    private void Start()
    {
        _playerShootingScript = GetComponent<PlayerShooting>();

        if (interfaceCanvas == null)
            interfaceCanvas = FindFirstObjectByType<Canvas>();

        if (handImage == null && interfaceCanvas != null)
        {
            var handTransform = interfaceCanvas.transform.Find("Hand");
            if (handTransform != null)
                handImage = handTransform.GetComponent<Image>();
        }

        if (gunImage == null && interfaceCanvas != null)
        {
            var gunTransform = interfaceCanvas.transform.Find("Gun");
            if (gunTransform != null)
                gunImage = gunTransform.GetComponent<Image>();
        }

        _throwAudio = GetComponent<AudioSource>();

        _spr1 = CreateSprite(tex1);
        _spr2 = CreateSprite(tex2);
        _spr3 = CreateSprite(tex3);
        _spr4 = CreateSprite(tex4);

        if (handImage != null)
        {
            handImage.enabled = false;
            handImage.color = Color.white;
        }

        if (playerCamera == null)
            playerCamera = GetComponentInChildren<CinemachineCamera>(true);
    }

    private void OnEnable()
    {
        if (switchToLine == null || switchToLine.action == null)
        {
            Debug.LogWarning("PlayerThrowingLine: 'switchToLine' InputActionReference is not assigned.");
            return;
        }

        switchToLine.action.Enable();
        switchToLine.action.performed += OnLineKey;
    }

    private void OnDisable()
    {
        if (switchToLine == null || switchToLine.action == null)
            return;

        switchToLine.action.performed -= OnLineKey;
        switchToLine.action.Disable();
    }

    private void OnLineKey(InputAction.CallbackContext _)
    {

        if (_playerShootingScript != null && _playerShootingScript.CanUseGun && _playerShootingScript.IsShootingNow)
            return;

        if (Time.time < _nextAllowedTime)
            return;

        _nextAllowedTime = Time.time + rateOfFire;

        Debug.Log("[PlayerThrowingLine] Q pressed -> spawn Line");
        SpawnLineProjectile();


        if (handImage != null && tex1 != null)
        {
            PlayLineThrowAnimation();
        }
    }

    private void SpawnLineProjectile()
    {
        if (linePrefab == null)
        {
            Debug.LogWarning("PlayerThrowingLine: linePrefab is null. Przypnij Assets/Prefabs/Line.prefab w Inspectorze.");
            return;
        }

        var spawnT = transform;

        Vector3 dir = spawnT.forward;
        if (playerCamera != null)
            dir = playerCamera.transform.forward;

        // obróć lekko w pionie (pitch) względem osi kamery/gracza
        if (Mathf.Abs(linePitchDegrees) > 0.001f)
        {
            var axis = playerCamera != null ? playerCamera.transform.right : spawnT.right;
            dir = Quaternion.AngleAxis(linePitchDegrees, axis) * dir;
        }

        var pos = spawnT.position;
        if (playerCamera != null)
            pos = playerCamera.transform.position + dir.normalized * 0.6f;

        var rot = Quaternion.LookRotation(dir.normalized);
        var line = Instantiate(linePrefab, pos, rot);
        line.Launch(dir, lineSpeed, lineLifetime);
    }

    private void PlayLineThrowAnimation()
    {
        if (handImage == null)
            return;

        if (_animCoroutine != null)
            StopCoroutine(_animCoroutine);

        _animCoroutine = StartCoroutine(LineThrowAnimRoutine());
    }

    private IEnumerator LineThrowAnimRoutine()
    {
        if (gunImage != null)
            gunImage.enabled = false;

        handImage.enabled = true;
        SetHandSprite(_spr1);

        if (_throwAudio != null && lineThrowingSound != null)
            _throwAudio.PlayOneShot(lineThrowingSound);

        if (frameTime > 0f)
        {
            if (_spr2 != null) { SetHandSprite(_spr2); yield return new WaitForSeconds(frameTime); }
            if (_spr3 != null) { SetHandSprite(_spr3); yield return new WaitForSeconds(frameTime); }
            if (_spr4 != null) { SetHandSprite(_spr4); yield return new WaitForSeconds(frameTime); }
        }

        SetHandSprite(_spr1);

        handImage.enabled = false;
        if (gunImage != null)
            gunImage.enabled = true;
    }

    private void SetHandSprite(Sprite s)
    {
        if (handImage == null)
            return;

        handImage.color = Color.white;
        if (s != null)
            handImage.sprite = s;
    }

    private static Sprite CreateSprite(Texture2D t)
    {
        if (t == null)
            return null;

        return Sprite.Create(t, new Rect(0, 0, t.width, t.height), new Vector2(0.5f, 0.5f), 100f);
    }
}

using System.Collections;
using Unity.Cinemachine;
using UnityEngine;
using UnityEngine.InputSystem;
using UnityEngine.UI;

[RequireComponent(typeof(AudioSource))]
public class PlayerThrowingLine : MonoBehaviour
{
    [Header("Input")]
    [Tooltip("Akcja pod Q (przełączenie na linę / rzut liną).")]
    [SerializeField] public InputActionReference switchToLine;

    private PlayerShooting _playerShootingScript;

    [Header("UI")]
    [SerializeField] private Image handImage;

    [Tooltip("Opcjonalnie: przypnij UI Image broni. Jeśli puste, skrypt spróbuje znaleźć child 'Gun' w Canvasie.")]
    [SerializeField] private Image gunImage;

    [SerializeField] public Canvas interfaceCanvas;

    [Header("Line Throw Animation")]
    [Tooltip("Czas na każdą klatkę rzutu (tex2->tex3->tex4).")]
    [SerializeField, Min(0f)] private float frameTime = 0.06f;

    [SerializeField] private Texture2D tex1;
    [SerializeField] private Texture2D tex2;
    [SerializeField] private Texture2D tex3;
    [SerializeField] private Texture2D tex4;

    [SerializeField] public AudioClip lineThrowingSound;
    private AudioSource _throwAudio;

    [Header("Line Projectile")]
    [SerializeField] private Line linePrefab;

    [SerializeField] private Transform lineSpawnPoint;
    [SerializeField] private Vector3 lineOriginLocalOffset = new Vector3(0f, -0.4f, 0f);

    [SerializeField, Min(0f)] private float rateOfFire = 0.5f;

    [SerializeField] private float lineSpeed = 30f;
    [SerializeField] private float lineLifetime = 2f;
    [SerializeField, Min(0.1f)] private float maxLineLength = 12f;
    [SerializeField, Min(0.1f)] private float lineRetractSpeed = 40f;

    [Header("Direction")]
    [SerializeField] private CinemachineCamera playerCamera;

    [SerializeField] private float linePitchDegrees = -10f;

    private Coroutine _animCoroutine;
    private Sprite _spr1, _spr2, _spr3, _spr4;
    private Line _activeLine;

    private float _nextAllowedTime;

    private void Start()
    {
        _playerShootingScript = GetComponent<PlayerShooting>();

        if (interfaceCanvas == null)
            interfaceCanvas = FindFirstObjectByType<Canvas>();

        if (handImage == null && interfaceCanvas != null)
        {
            var handTransform = interfaceCanvas.transform.Find("Hand");
            if (handTransform != null)
                handImage = handTransform.GetComponent<Image>();
        }

        if (gunImage == null && interfaceCanvas != null)
        {
            var gunTransform = interfaceCanvas.transform.Find("Gun");
            if (gunTransform != null)
                gunImage = gunTransform.GetComponent<Image>();
        }

        _throwAudio = GetComponent<AudioSource>();

        _spr1 = CreateSprite(tex1);
        _spr2 = CreateSprite(tex2);
        _spr3 = CreateSprite(tex3);
        _spr4 = CreateSprite(tex4);

        if (handImage != null)
        {
            handImage.enabled = false;
            handImage.color = Color.white;
        }

        if (playerCamera == null)
            playerCamera = GetComponentInChildren<CinemachineCamera>(true);
    }

    private void OnEnable()
    {
        if (switchToLine == null || switchToLine.action == null)
        {
            Debug.LogWarning("PlayerThrowingLine: 'switchToLine' InputActionReference is not assigned.");
            return;
        }

        switchToLine.action.Enable();
        switchToLine.action.performed += OnLineKey;
    }

    private void OnDisable()
    {
        if (switchToLine == null || switchToLine.action == null)
            return;

        switchToLine.action.performed -= OnLineKey;
        switchToLine.action.Disable();
    }

    private void OnLineKey(InputAction.CallbackContext _)
    {
        if (_playerShootingScript != null && _playerShootingScript.CanUseGun && _playerShootingScript.IsShootingNow)
            return;

        if (_activeLine != null && !_activeLine.IsFinished)
            return;

        if (Time.time < _nextAllowedTime)
            return;

        _nextAllowedTime = Time.time + rateOfFire;

        Debug.Log("[PlayerThrowingLine] Q pressed -> spawn Line");
        SpawnLineProjectile();


        if (handImage != null && tex1 != null)
        {
            PlayLineThrowAnimation();
        }
    }

    private void SpawnLineProjectile()
    {
        if (linePrefab == null)
        {
            Debug.LogWarning("PlayerThrowingLine: linePrefab is null. Przypnij Assets/Prefabs/Line.prefab w Inspectorze.");
            return;
        }

        var spawnT = lineSpawnPoint != null ? lineSpawnPoint : transform;
        var aimT = playerCamera != null ? playerCamera.transform : spawnT;

        Vector3 dir = aimT.forward;

        // obróć lekko w pionie (pitch) względem osi kamery/gracza
        if (Mathf.Abs(linePitchDegrees) > 0.001f)
        {
            var axis = aimT.right;
            dir = Quaternion.AngleAxis(linePitchDegrees, axis) * dir;
        }

        var pos = spawnT.TransformPoint(lineOriginLocalOffset);
        var rot = Quaternion.LookRotation(dir.normalized);

        _activeLine = Instantiate(linePrefab, pos, rot);
        _activeLine.Launch(spawnT, lineOriginLocalOffset, dir, lineSpeed, maxLineLength, lineLifetime, lineRetractSpeed);
    }

    private void PlayLineThrowAnimation()
    {
        if (handImage == null)
            return;

        if (_animCoroutine != null)
            StopCoroutine(_animCoroutine);

        _animCoroutine = StartCoroutine(LineThrowAnimRoutine());
    }

    private IEnumerator LineThrowAnimRoutine()
    {
        if (gunImage != null)
            gunImage.enabled = false;

        handImage.enabled = true;
        SetHandSprite(_spr1);

        if (_throwAudio != null && lineThrowingSound != null)
            _throwAudio.PlayOneShot(lineThrowingSound);

        if (frameTime > 0f)
        {
            if (_spr2 != null) { SetHandSprite(_spr2); yield return new WaitForSeconds(frameTime); }
            if (_spr3 != null) { SetHandSprite(_spr3); yield return new WaitForSeconds(frameTime); }
            if (_spr4 != null) { SetHandSprite(_spr4); yield return new WaitForSeconds(frameTime); }
        }

        SetHandSprite(_spr1);

        handImage.enabled = false;
        if (gunImage != null)
            gunImage.enabled = true;
    }

    private void SetHandSprite(Sprite s)
    {
        if (handImage == null)
            return;

        handImage.color = Color.white;
        if (s != null)
            handImage.sprite = s;
    }

    private static Sprite CreateSprite(Texture2D t)
    {
        if (t == null)
            return null;

        return Sprite.Create(t, new Rect(0, 0, t.width, t.height), new Vector2(0.5f, 0.5f), 100f);
    }
}
